code_changes.content:
[
  {
    "file": "source/common/http/header_utility.cc",
    "line": 43,
    "severity": "critical",
    "description": "Inverted logic in HeaderUtility::matchHeaders(). The function returns false when a header matches, but should return true. When header filters are configured, the function should return true if ANY of the configured headers match the request headers. Currently, it returns false on match and true on no-match, which is backwards. This breaks fault injection and RBAC header matching across the codebase.",
    "fix_patch": "--- a/source/common/http/header_utility.cc
+++ b/source/common/http/header_utility.cc
@@ -40,7 +40,7 @@ bool HeaderUtility::matchHeaders(const HeaderMap& request_headers,
   // No headers to match is considered a match.
   if (!config_headers.empty()) {
     for (const HeaderDataPtr& cfg_header_data : config_headers) {
-      if (cfg_header_data->matchesHeaders(request_headers)) {
+      if (!cfg_header_data->matchesHeaders(request_headers)) {
         return false;
       }
     }
"
  },
  {
    "file": "source/extensions/filters/http/fault/fault_filter.cc",
    "line": 462,
    "severity": "critical",
    "description": "Gauge leak and incorrect decrement logic in FaultFilter::postDelayInjection(). The condition checks if response rate limit is CONFIGURED (globally) rather than if a response rate LIMITER was ACTUALLY CREATED for this request. This causes: (1) active_faults_ gauge to leak when response rate limit is configured but not enabled for the request, and (2) incorrect gauge management when both delay and response rate limit are active. The fix should check if response_limiter_ is not null instead of checking isResponseRateLimitConfigured().",
    "fix_patch": "--- a/source/extensions/filters/http/fault/fault_filter.cc
+++ b/source/extensions/filters/http/fault/fault_filter.cc
@@ -459,7 +459,7 @@ void FaultFilter::postDelayInjection(const Http::RequestHeaderMap& request_head
     // of fault is active. As the delay timer is always done at this point and followed abort faults
     // have been checked earlier, here we just check if there's a response rate limit configured.
     ASSERT(fault_active_);
     ASSERT(delay_timer_ == nullptr);
-    if (isResponseRateLimitConfigured()) {
+    if (response_limiter_ == nullptr) {
       config_->stats().active_faults_.dec();
       fault_active_ = false;
     }
"
  },
  {
    "file": "source/common/http/filter_manager.cc",
    "line": 1294,
    "severity": "critical",
    "description": "Inverted condition in required response header validation. The code checks `if (status.ok())` and then sends a BadGateway error, but the comment explicitly says 'If the check failed, then we reply with BadGateway'. The logic is backwards - when the status is OK (check passed), the code should NOT send an error. This causes all valid responses to be rejected with BadGateway errors, and allows invalid responses to pass through.",
    "fix_patch": "--- a/source/common/http/filter_manager.cc
+++ b/source/common/http/filter_manager.cc
@@ -1291,7 +1291,7 @@ void FilterManager::encodeHeaders(ResponseHeaderMap& headers, bool end_stream,
   // See the previous attempt (#15658) for detail, and for now we choose to protect only against
   // filter chains.
   const auto status = HeaderUtility::checkRequiredResponseHeaders(headers);
-  if (status.ok()) {
+  if (!status.ok()) {
     // If the check failed, then we reply with BadGateway, and stop the further processing.
     sendLocalReply(
         Http::Code::BadGateway, status.message(), nullptr, absl::nullopt,
"
  },
  {
    "file": "source/extensions/filters/http/ext_authz/ext_authz.cc",
    "line": 728,
    "severity": "high",
    "description": "Missing route cache clearance in ext_authz filter when request headers are modified. The ext_authz filter modifies request headers (header additions, removals, query parameter changes) that affect routing decisions. When config_->clearRouteCache() is true, the route cache must be cleared before continuing, so downstream filters see the updated route. Currently, the route cache is never cleared, causing routing decisions to be based on stale header state. The comment at line 502 incorrectly claims 'Route cache clearing handled by downstream filters' but this is not reliable.",
    "fix_patch": "--- a/source/extensions/filters/http/ext_authz/ext_authz.cc
+++ b/source/extensions/filters/http/ext_authz/ext_authz.cc
@@ -725,6 +725,9 @@ void Filter::onComplete(Filters::Common::ExtAuthz::ResponsePtr&& response) {
     if (cluster_) {
       config_->incCounter(cluster_->statsScope(), config_->ext_authz_ok_);
     }
+    if (config_->clearRouteCache()) {
+      decoder_callbacks_->clearRouteCache();
+    }
     stats_.ok_.inc();
     continueDecoding();
     break;
"
  }
]

